const body = $input.first().json;
const data = body.data || body;
const from = data.key?.remoteJid || data.remoteJid || 'unknown';
const msgType = data.messageType || 'conversation';
const message = data.message || {};
let text = '';
if (msgType === 'conversation') { text = message.conversation || ''; }
else if (msgType === 'extendedTextMessage') { text = message.extendedTextMessage?.text || ''; }
else { text = JSON.stringify(message).substring(0, 200); }
const t = text.toLowerCase().trim();
let intent = 'UNKNOWN';
if (t.includes('grant') || t.includes('nofa') || t.includes('eaf') || t.includes('earn')) { intent = 'GRANT'; }
else if (t.includes('3pl') || t.includes('logistics') || t.includes('shipment') || t.includes('inventory')) { intent = 'TPL'; }
else if (t.includes('status') || t.includes('briefing') || t.includes('morning') || t.includes('brief')) { intent = 'BRIEF'; }
else if (t.includes('monk') || t.includes('drone') || t.includes('akms') || t.includes('cako') || t.includes('architect')) { intent = 'TECH'; }
else if (t === 'help' || t === '?') { intent = 'HELP'; }
else if (t.startsWith('ack ')) { intent = 'ACK'; }
return [{ json: { intent, text, from, timestamp: new Date().toISOString() } }];

const text = $('Parse Intent').first().json.text;
const shipId = text.replace(/^ack\s+/i, '').trim();
return [{ json: { reply: `Shipment *${shipId}* acknowledged.\nLogged: ${new Date().toISOString()}\nAlerts suppressed 4 hours.` } }];

let reply = '';
const branches = ['Morning Brief','Tech Brief','Help Menu','Acknowledge','Unknown Intent'];
for (const name of branches) {
  try { const v = $(name).first()?.json?.reply; if (v) { reply = v; break; } } catch(e) {}
}
if (!reply) { reply = 'Request processed. Check /data/Aidan_Outputs/ for the full report.'; }
if (reply.length > 3800) { reply = reply.substring(0, 3800) + '\n_(Full report in /data/Aidan_Outputs/)'; }
const from = $('Parse Intent').first().json.from;
return [{ json: { reply, from } }];
